class Solution(object):
    def sumImbalanceNumbers(self, nums):
        n = len(nums)
        ans = 0
        for i in range(n):
            seen = set()
            imbalance = 0
            seen.add(nums[i])
            for j in range(i + 1, n):
                v = nums[j]
                if v not in seen:
                    has_left = (v - 1) in seen
                    has_right = (v + 1) in seen
                    if not has_left and not has_right:
                        imbalance += 1  # creates new gap on both sides
                    elif has_left and has_right:
                        imbalance -= 1  # bridges a gap
                    # one neighbor: no change (fills one gap, creates none)
                    seen.add(v)
                ans += imbalance
        return ans
